// NewAuditFormatter creates a new AuditFormatter with optional event logging support.
func NewAuditFormatter(salter Salter, useEventLogger bool) (*AuditFormatter, error) {
	if salter == nil {
		return nil, errors.New("cannot create a new audit formatter with nil salter")
	}

	return &AuditFormatter{salter: salter, useEventLogger: useEventLogger}, nil
}

