// NewAuditFormatterWriter creates a new AuditFormatterWriter and embeds the given formatter.
func NewAuditFormatterWriter(formatter Formatter, writer Writer, useEventLogger bool) (*AuditFormatterWriter, error) {
	switch {
	case formatter == nil:
		return nil, errors.New("cannot create a new audit formatter writer with nil formatter")
	case writer == nil:
		return nil, errors.New("cannot create a new audit formatter writer with nil writer")
	}

	fw := &AuditFormatterWriter{
		Formatter:  formatter,
		Writer:     writer,
		useEventLogger: useEventLogger,
	}

	return fw, nil
}

